import React, { useRef, useEffect, useMemo } from 'react';
import { useLanguage } from '../contexts/LanguageContext';
import { getKeyboardConfig } from '../config/keyboardLoader';

// ── Finger colours ────────────────────────────────────────────────────────────
const FC = {
  lp:'#f87171', lr:'#fb923c', lm:'#eab308', li:'#4ade80',
  ri:'#34d399', rm:'#60a5fa', rr:'#a78bfa', rp:'#f472b6', th:'#94a3b8',
};

// Bilingual finger names — Punjabi text only shown when language === 'punjabi'
const FN = {
  lp:{ en:'Left Pinky',   pu:'ਖੱਬੀ ਕਾਨੀ' },
  lr:{ en:'Left Ring',    pu:'ਖੱਬੀ ਅਨਾਮਿਕਾ' },
  lm:{ en:'Left Middle',  pu:'ਖੱਬੀ ਵਿਚਕਾਰਲੀ' },
  li:{ en:'Left Index',   pu:'ਖੱਬੀ ਤਰਜਨੀ' },
  ri:{ en:'Right Index',  pu:'ਸੱਜੀ ਤਰਜਨੀ' },
  rm:{ en:'Right Middle', pu:'ਸੱਜੀ ਵਿਚਕਾਰਲੀ' },
  rr:{ en:'Right Ring',   pu:'ਸੱਜੀ ਅਨਾਮਿਕਾ' },
  rp:{ en:'Right Pinky',  pu:'ਸੱਜੀ ਕਾਨੀ' },
  th:{ en:'Thumb',        pu:'ਅੰਗੂਠਾ' },
};

// Hardcoded English finger map — used for BOTH English layout AND as fallback for Punjabi
// Keys are lowercase physical key ids matching the layout arrays
const EFM = {
  '`':'lp','1':'lp','q':'lp','a':'lp','z':'lp','tab':'lp','caps':'lp','sl':'lp',
  '2':'lr','w':'lr','s':'lr','x':'lr',
  '3':'lm','e':'lm','d':'lm','c':'lm',
  '4':'li','5':'li','r':'li','t':'li','f':'li','g':'li','v':'li','b':'li',
  '6':'ri','7':'ri','y':'ri','u':'ri','h':'ri','j':'ri','n':'ri','m':'ri',
  '8':'rm','i':'rm','k':'rm',',':'rm',
  '9':'rr','o':'rr','l':'rr','.':'rr',
  '0':'rp','-':'rp','=':'rp','p':'rp','[':'rp',']':'rp','\\':'rp',
  ';':'rp',"'":'rp','/':'rp','enter':'rp','bs':'rp','sr':'rp',' ':'th',
};

// Shift mechanics: left-hand key → press Right Shift (sr); right-hand key → press Left Shift (sl)
const getShiftKey = (fc) => fc?.startsWith('l') ? 'sr' : 'sl';
const getShiftFc  = (fc) => fc?.startsWith('l') ? 'rp' : 'lp';

// ── Dimensions — UNIT=52 gives a wider keyboard ───────────────────────────────
const UNIT = 52;
const GAP  = 3;
const CARD_H = 42;

// Wide key multipliers
const WIDES = { bs:2, tab:1.5, caps:1.75, enter:2.25, sl:2.25, sr:2.75, ' ':10 };
const SPEC_LABELS = { bs:'⌫', tab:'Tab', caps:'Caps', enter:'↵', sl:'Shift', sr:'Shift', ' ':'Space' };

const kw = (id) => WIDES[id] ? WIDES[id] * UNIT + (WIDES[id] - 1) * GAP : UNIT;

// ── Mini Hand ─────────────────────────────────────────────────────────────────
function MiniHand({ side, activeFingers }) {
  const fingers = side === 'left'
    ? [['lp',0.62],['lr',0.82],['lm',1.0],['li',0.86],['th',0.5]]
    : [['th',0.5], ['ri',0.86],['rm',1.0], ['rr',0.82],['rp',0.62]];
  return (
    <div style={{ display:'flex', alignItems:'flex-end', gap:2, height:CARD_H, flexShrink:0, paddingBottom:3 }}>
      {fingers.map(([fid, ratio]) => {
        const on    = activeFingers.includes(fid);
        const color = FC[fid];
        const h     = Math.round(26 * ratio);
        return (
          <div key={fid} style={{
            width: fid === 'th' ? 7 : 9,
            height: h,
            borderRadius: fid === 'th' ? '4px 4px 2px 6px' : '5px 5px 2px 2px',
            background: on ? color : '#e2e8f0',
            border: `1.5px solid ${on ? color : '#d1d5db'}`,
            boxShadow: on ? `0 0 7px ${color}cc` : 'none',
            transition: 'all 0.12s',
          }}/>
        );
      })}
    </div>
  );
}

// ── Suggestion Box ────────────────────────────────────────────────────────────
function SuggestionBox({ activeKey, physKey, charFc, needShift, isPunjabi }) {
  // Empty state
  if (!activeKey || !charFc) return (
    <div style={{ padding:'0 24px', display:'flex', alignItems:'center', justifyContent:'center', height:CARD_H }}>
      <span style={{ color:'#cbd5e1', fontSize:12 }}>Start typing…</span>
    </div>
  );

  const color   = FC[charFc] || '#94a3b8';
  const fn      = FN[charFc] || { en:'', pu:'' };
  const shiftFc = needShift ? getShiftFc(charFc) : null;
  const shiftFn = shiftFc   ? FN[shiftFc]        : null;

  const card = (hi, extra = {}) => ({
    height: CARD_H, borderRadius: 9, flexShrink: 0,
    background: hi ? `${color}10` : '#fff',
    border: `1.5px solid ${hi ? color + '55' : '#e8ecf0'}`,
    boxShadow: hi ? `0 2px 8px ${color}18` : '0 1px 3px rgba(0,0,0,0.04)',
    display: 'flex', alignItems: 'center', justifyContent: 'center',
    ...extra,
  });

  const Arrow = () => (
    <span style={{ color:'#d1d5db', fontSize:15, flexShrink:0, width:14, textAlign:'center' }}>›</span>
  );

  // Type card label — Punjabi uses Gurmukhi font; English uses monospace
  const typeFont  = isPunjabi ? "'Raavi','Noto Sans Gurmukhi',sans-serif" : "'Courier New',monospace";
  const typeLabel = activeKey === ' ' ? '␣' : activeKey;
  // Key card label
  const keyLabel  = physKey === ' ' ? 'SPC' : physKey.toUpperCase();

  return (
    <div style={{ display:'flex', alignItems:'center', gap:3, padding:'0 12px', flexShrink:0 }}>

      {/* TYPE */}
      <div style={card(true, { padding:'0 18px' })}>
        <span style={{ fontFamily:typeFont, fontSize:26, fontWeight:900, color, lineHeight:1 }}>
          {typeLabel}
        </span>
      </div>

      <Arrow/>

      {/* SHIFT — only when needed (Punjabi shift characters) */}
      {needShift && (
        <>
          <div style={card(false, { padding:'0 14px', gap:8 })}>
            <span style={{ fontSize:18, fontWeight:900, color:FC[shiftFc], fontFamily:'monospace', lineHeight:1 }}>⇧</span>
            <div style={{ display:'flex', flexDirection:'column', gap:1 }}>
              <span style={{ fontSize:11, fontWeight:800, color:FC[shiftFc], whiteSpace:'nowrap', lineHeight:1 }}>Shift</span>
              <span style={{ fontSize:10, fontWeight:600, color:FC[shiftFc]+'aa', whiteSpace:'nowrap', lineHeight:1 }}>{shiftFn?.en}</span>
            </div>
          </div>
          <Arrow/>
        </>
      )}

      {/* KEY */}
      <div style={card(true, { padding:'0 18px' })}>
        <span style={{ fontSize:22, fontWeight:900, color, fontFamily:"'Courier New',monospace", lineHeight:1 }}>
          {keyLabel}
        </span>
      </div>

      <Arrow/>

      {/* FINGER — English name always shown; Punjabi name only in Punjabi mode */}
      <div style={card(false, {
        padding:'0 14px', flexDirection:'column',
        alignItems:'flex-start', justifyContent:'center',
        gap: isPunjabi ? 3 : 0,
      })}>
        <div style={{ display:'flex', alignItems:'center', gap:6 }}>
          <div style={{ width:7, height:7, borderRadius:'50%', background:color, flexShrink:0, boxShadow:`0 0 5px ${color}88` }}/>
          <span style={{ fontSize:12, fontWeight:700, color:'#334155', whiteSpace:'nowrap' }}>{fn.en}</span>
        </div>
        {isPunjabi && (
          <span style={{ fontSize:12, color:'#64748b', lineHeight:1, fontFamily:"'Raavi',sans-serif", whiteSpace:'nowrap', paddingLeft:13 }}>
            {fn.pu}
          </span>
        )}
      </div>

    </div>
  );
}

// ── Main Component ────────────────────────────────────────────────────────────
const VirtualKeyboard = ({ activeKey, isCorrect }) => {
  const lastKeyRef     = useRef(null);
  const lastCorrectRef = useRef(null);

  const { language } = useLanguage();
  const { layout: keyboardLayout, fingerMap: layoutFingerMap } = getKeyboardConfig(language);
  const isPunjabi = language === 'punjabi';

  // ── Sound ─────────────────────────────────────────────────────────────────
  useEffect(() => {
    if (isCorrect === null || isCorrect === undefined) return;
    if (lastKeyRef.current === activeKey && lastCorrectRef.current === isCorrect) return;
    lastKeyRef.current     = activeKey;
    lastCorrectRef.current = isCorrect;
    isCorrect ? playTick() : playTock();
  }, [isCorrect, activeKey]); // eslint-disable-line

  const playTick = () => {
    try {
      const ctx  = new (window.AudioContext || window.webkitAudioContext)();
      const osc  = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain); gain.connect(ctx.destination);
      osc.type = 'triangle';
      osc.frequency.setValueAtTime(900, ctx.currentTime);
      gain.gain.setValueAtTime(0.07, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.035);
      osc.start(ctx.currentTime); osc.stop(ctx.currentTime + 0.035);
      osc.onended = () => ctx.close();
    } catch (e) {}
  };

  const playTock = () => {
    try {
      const ctx  = new (window.AudioContext || window.webkitAudioContext)();
      const osc  = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain); gain.connect(ctx.destination);
      osc.type = 'sine';
      osc.frequency.setValueAtTime(280, ctx.currentTime);
      gain.gain.setValueAtTime(0.06, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.055);
      osc.start(ctx.currentTime); osc.stop(ctx.currentTime + 0.055);
      osc.onended = () => ctx.close();
    } catch (e) {}
  };

  // ── Normalize a layout entry ──────────────────────────────────────────────
  // English layout: plain strings like 'a', 'b', 'tab'
  // Punjabi layout: objects like { key:'a', display:'ੋ', shift:'ਓ' }
  const norm = (entry) => {
    if (typeof entry === 'string') {
      return { id: entry, label: entry, shiftLabel: null };
    }
    return {
      id:         entry.key     || '',
      label:      entry.display || entry.key || '',
      shiftLabel: entry.shift   || null,
    };
  };

  // ── Reverse map: Gurmukhi char → physical key id (Punjabi only) ───────────
  const reverseMap = useMemo(() => {
    const map = {};
    if (!isPunjabi) return map;
    keyboardLayout.forEach(row => row.forEach(entry => {
      if (typeof entry === 'object' && entry.key) {
        if (entry.display) map[entry.display] = entry.key;
        if (entry.shift)   map[entry.shift]   = entry.key;
      }
    }));
    return map;
  }, [keyboardLayout, isPunjabi]);

  // ── Resolve physical key id from the active character ─────────────────────
  // For English: activeKey IS the physical key (e.g. 'a')
  // For Punjabi: look up in reverseMap (e.g. 'ਕ' → 'k')
  const resolvePhysKey = (char) => {
    if (!char) return '';
    if (char === ' ') return ' ';
    if (isPunjabi && reverseMap[char]) return reverseMap[char];
    return char.toLowerCase();
  };

  // ── Finger for a physical key id ─────────────────────────────────────────
  // For English: always use EFM (the hardcoded map)
  // For Punjabi: try layoutFingerMap first, then fall back to EFM
  const fingerFor = (id) => {
    if (!id) return '';
    const key = id.toLowerCase();
    if (isPunjabi) {
      return (layoutFingerMap && (layoutFingerMap[id] || layoutFingerMap[key])) || EFM[key] || '';
    }
    // English — always use EFM directly
    return EFM[key] || '';
  };

  // ── Compute active key state ──────────────────────────────────────────────
  const physKey = resolvePhysKey(activeKey);
  const charFc  = fingerFor(physKey);

  // Shift needed only for Punjabi shift characters
  const needShift = useMemo(() => {
    if (!isPunjabi || !activeKey || activeKey === ' ') return false;
    // If the active character is a shift-layer character in the layout
    return keyboardLayout.flat().some(e => typeof e === 'object' && e.shift === activeKey);
  }, [isPunjabi, activeKey, keyboardLayout]);

  const shiftFc  = needShift ? getShiftFc(charFc)  : null;
  const shiftKey = needShift ? getShiftKey(charFc)  : null;

  // Which fingers to glow on each hand
  const leftActive  = [charFc, shiftFc].filter(fc => fc?.startsWith('l'));
  const rightActive = [charFc, shiftFc].filter(fc => fc?.startsWith('r'));
  if (charFc === 'th' || shiftFc === 'th') { leftActive.push('th'); rightActive.push('th'); }

  // ── Key highlight logic ───────────────────────────────────────────────────
  const isKeyActive = (entry) => {
    if (!activeKey) return false;
    const { id, label, shiftLabel } = norm(entry);
    if (id === ' ' || id === 'SPACE') return activeKey === ' ';

    if (isPunjabi) {
      // Punjabi: match by display char or shift char
      return label === activeKey || shiftLabel === activeKey;
    } else {
      // English: match by lowercase key id vs lowercase activeKey
      return id.toLowerCase() === activeKey.toLowerCase();
    }
  };

  const isShiftActive = (id) => needShift && id === shiftKey;

  const getDisplayLabel = (entry) => {
    const { id, label } = norm(entry);
    return SPEC_LABELS[id] ?? label;
  };

  // ── Render ────────────────────────────────────────────────────────────────
  return (
    /* Scroll wrapper so keyboard is never clipped on smaller screens */
    <div style={{ overflowX:'auto', overflowY:'hidden', padding:'0 4px' }}>
      <div style={{
        background: '#f8fafc',
        borderRadius: 16,
        padding: '12px 10px 10px',
        border: '1px solid #e2e8f0',
        boxShadow: '0 4px 24px rgba(0,0,0,0.06)',
        userSelect: 'none',
        width: 'fit-content',
        minWidth: 'max-content',
        margin: '0 auto',
        fontFamily: "'Segoe UI',sans-serif",
      }}>

        {/* ── Guidance row: [left hand] [suggestion cards] [right hand] ── */}
        <div style={{
          display:'flex', alignItems:'center', justifyContent:'center',
          marginBottom:10, gap:8,
        }}>
          <MiniHand side="left"  activeFingers={leftActive}/>
          <SuggestionBox
            activeKey={activeKey}
            physKey={physKey}
            charFc={charFc}
            needShift={needShift}
            isPunjabi={isPunjabi}
          />
          <MiniHand side="right" activeFingers={rightActive}/>
        </div>

        {/* ── Key rows ── */}
        {keyboardLayout.map((row, ri) => (
          <div key={ri} style={{ display:'flex', gap:GAP, marginBottom:GAP, justifyContent:'center' }}>
            {row.map((entry, ki) => {
              const { id, shiftLabel } = norm(entry);
              const fc      = fingerFor(id) || 'th';
              const col     = FC[fc] || '#94a3b8';
              const isMain  = isKeyActive(entry);
              const isSh    = isShiftActive(id);
              const isAct   = isMain || isSh;
              const actCol  = isSh && !isMain ? FC[shiftFc] || col : col;
              const spec    = !!WIDES[id];
              const w       = kw(id);
              // English label top-right: only on Punjabi layout
              const engLabel = isPunjabi && !spec && id.length === 1 ? id.toUpperCase() : null;

              return (
                <div key={`${ri}-${ki}`} style={{
                  width: w, height: UNIT, borderRadius: 7,
                  background: isAct ? actCol : '#fff',
                  border: `1.5px solid ${isAct ? actCol : '#e2e8f0'}`,
                  boxShadow: isAct ? `0 3px 12px ${actCol}55` : '0 1px 3px rgba(0,0,0,0.05)',
                  position: 'relative', transition: 'all 0.07s',
                  transform: isAct ? 'translateY(1px)' : 'none',
                  cursor: 'default', overflow: 'hidden',
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                }}>
                  {/* Punjabi layout only: shift char top-left, English key top-right */}
                  {isPunjabi && !spec && (
                    <>
                      {shiftLabel && (
                        <span style={{
                          position:'absolute', top:2, left:4,
                          fontSize:13, lineHeight:1, fontWeight:800,
                          color: isAct ? 'rgba(255,255,255,0.8)' : '#94a3b8',
                          fontFamily:"'Raavi','Noto Sans Gurmukhi',sans-serif",
                        }}>{shiftLabel}</span>
                      )}
                      {engLabel && (
                        <span style={{
                          position:'absolute', top:2, right:3,
                          fontSize:10, lineHeight:1, fontWeight:900,
                          color: isAct ? 'rgba(255,255,255,0.55)' : `${col}cc`,
                          fontFamily:'monospace',
                        }}>{engLabel}</span>
                      )}
                    </>
                  )}

                  {/* Main label */}
                  <span style={{
                    position: 'absolute',
                    // Punjabi normal keys: bottom-anchored so there's room for shift char top-left
                    bottom: (spec || !isPunjabi) ? 'auto' : 3,
                    left:0, right:0, textAlign:'center',
                    fontSize: spec ? 11 : (isPunjabi ? 18 : 20),
                    lineHeight: 1, fontWeight: 800,
                    color: isAct ? '#fff' : '#1e293b',
                    fontFamily: isPunjabi
                      ? "'Raavi','Noto Sans Gurmukhi',sans-serif"
                      : "'Courier New',monospace",
                  }}>{getDisplayLabel(entry)}</span>
                </div>
              );
            })}
          </div>
        ))}

        {/* Home row hint */}
        <div style={{ textAlign:'center', marginTop:5, fontSize:9, color:'#94a3b8', letterSpacing:2 }}>
          {isPunjabi
            ? 'HOME ROW · ੋ ੇ ੍ ਿ ੁ  |  ਪ ਰ ਕ ਤ ਚ'
            : 'HOME ROW · A S D F  |  J K L ;'}
        </div>
      </div>
    </div>
  );
};

export default VirtualKeyboard;
